class Solution:
    def maximumSubarraySum(self, nums, k):
        best = None
        n = len(nums)
        for i in range(n):
            for j in range(i+1, n):
                if abs(nums[i] - nums[j]) == k:
                    s = sum(nums[i:j+1])
                    if best is None or s > best:
                        best = s
        return best if best is not None else 0

